import { forwardRef } from "react";
import type { HTMLAttributes, ReactNode } from "react";
import * as styles from "./Hint.css";
import { clsx } from "clsx";

export interface HintCustomProps {
  /**
   * The hint text content
   */
  children: ReactNode;
}

export interface HintProps
  extends
    Omit<HTMLAttributes<HTMLSpanElement>, keyof HintCustomProps>,
    HintCustomProps {}

export const Hint = forwardRef<HTMLSpanElement, HintProps>(
  ({ children, className, ...props }, ref) => {
    return (
      <span ref={ref} className={clsx(styles.hint, className)} {...props}>
        {children}
      </span>
    );
  }
);

Hint.displayName = "Hint";
